const init = () => {
    const cfg = {
        version: 14,
        topicBase: 'equipo1/jarabe/tambo_01',
        thingName: 'equipo1_jarabe_tambo_01',

        tempIdeal: 23, tempMinAlerta: 20, tempMaxAlerta: 25,
        tempTolerancia: 0.5, tempRisePerTick: 0.8, tempCoolPerTick: 0.8,

        volumenIdeal: 70, volumenMinAlerta: 20, volumenMaxAlerta: 85,
        volumenRisePerTick: 5, volumenDrainPerTick: 5,

        concIdeal: 65, concMin: 64, concMax: 67,
        concRisePerTick: 0.5, concDrainPerTick: 0.5, concCorrectRate: 0.1
    };

    const plant = {
        tempC: 23, volumen: 70, concentracion: 65,
        modoAumentoTemp: false, modoDisminucionTemp: false,
        modoAumentoVol: false, modoDisminucionVol: false,
        modoLlenado: false,
        modoAumentoConc: false, modoDisminucionConc: false,
        msgTempEnviado: 'estable', msgVolEnviado: 'estable', msgConcEnviado: 'normal'
    };

    const shadow = {
        reported: {
            valvula_salida: false,
            bomba_mezcla: false,
            enfriamiento: false,
            calentamiento: false,
            alert_led: false,
            led_concentracion: 'VERDE',
            potencia_motor: 70
        }
    };
    global.set('CFG', cfg); global.set('PLANT', plant); global.set('SHADOW', shadow);
};

let cfg = global.get('CFG');
let plant = global.get('PLANT');
let shadow = global.get('SHADOW');

if (!cfg || cfg.version !== 11) { 
    init(); 
    cfg = global.get('CFG'); 
    plant = global.get('PLANT'); 
    shadow = global.get('SHADOW'); 
}

const topic = msg.topic || "";
const isTick = topic.endsWith('/tick');
let event = null;

if (topic === 'action/reset') {
    init(); 
    cfg = global.get('CFG');
    plant = global.get('PLANT');
    shadow = global.get('SHADOW');
}
if (topic === 'action/aumento_temperatura') plant.modoAumentoTemp = true;
if (topic === 'action/disminucion_temperatura') plant.modoDisminucionTemp = true;
if (topic === 'action/aumento_volumen') plant.modoAumentoVol = true;
if (topic === 'action/disminucion_volumen') plant.modoDisminucionVol = true;
if (topic === 'action/llenar_tanque') plant.modoLlenado = true;
if (topic === 'action/aumento_concentracion') plant.modoAumentoConc = true;
if (topic === 'action/disminucion_concentracion') plant.modoDisminucionConc = true;

if (isTick) {
    // === AUTOREGULACIÓN (CON INERCIA): DEJA QUE EL ERROR CREZCA ANTES DE VENCER LA FALLA ===
    if (plant.tempC > cfg.tempMaxAlerta + 1.5) plant.modoAumentoTemp = false;
    if (plant.tempC < cfg.tempMinAlerta - 1.5) plant.modoDisminucionTemp = false;
    if (plant.volumen > cfg.volumenMaxAlerta + 4) plant.modoAumentoVol = false;
    if (plant.concentracion > cfg.concMax + 2) plant.modoAumentoConc = false;
    if (plant.concentracion < cfg.concMin - 2) plant.modoDisminucionConc = false;
    // (Omitimos volumenMinAlerta porque el tanque se debe seguir vaciando hasta 0)

    // Lógica Temperatura
    if (plant.modoAumentoTemp) {
        plant.tempC += cfg.tempRisePerTick;
    } else if (plant.modoDisminucionTemp) {
        plant.tempC -= cfg.tempCoolPerTick;
    } else if (shadow.reported.enfriamiento) {
        plant.tempC -= cfg.tempCoolPerTick;
        if (plant.tempC <= cfg.tempIdeal) {
            plant.tempC = cfg.tempIdeal;
            shadow.reported.enfriamiento = false; 
        }
    } else if (shadow.reported.calentamiento) {
        plant.tempC += cfg.tempRisePerTick;
        if (plant.tempC >= cfg.tempIdeal) {
            plant.tempC = cfg.tempIdeal;
            shadow.reported.calentamiento = false; 
        }
    }

    // Lógica Volumen
    if (plant.modoAumentoVol) {
        plant.volumen += cfg.volumenRisePerTick;
    } else if (plant.modoDisminucionVol) {
        plant.volumen -= cfg.volumenDrainPerTick;
        if (plant.volumen <= 0) {
            plant.volumen = 0;
            plant.modoDisminucionVol = false; // Detener en 0
        }
    } else if (plant.modoLlenado) {
        plant.volumen += cfg.volumenRisePerTick;
        if (plant.volumen >= cfg.volumenIdeal) {
            plant.volumen = cfg.volumenIdeal;
            plant.modoLlenado = false;
        }
    } else if (shadow.reported.valvula_salida) {
        plant.volumen -= cfg.volumenDrainPerTick;
        if (plant.volumen <= cfg.volumenIdeal) {
            plant.volumen = cfg.volumenIdeal;
            shadow.reported.valvula_salida = false; 
        }
    }

    // Lógica Concentración
    if (plant.modoAumentoConc) {
        plant.concentracion += cfg.concRisePerTick;
    } else if (plant.modoDisminucionConc) {
        plant.concentracion -= cfg.concDrainPerTick;
    } else if (shadow.reported.bomba_mezcla) {
        plant.concentracion += (cfg.concIdeal - plant.concentracion) * cfg.concCorrectRate;
        if (Math.abs(plant.concentracion - cfg.concIdeal) < 0.2) {
            plant.concentracion = cfg.concIdeal;
        }
    }

    plant.tempC = Math.round(plant.tempC * 10) / 10;
    plant.volumen = Math.round(plant.volumen * 10) / 10;
    plant.concentracion = Math.round(plant.concentracion * 10) / 10;
}

if (plant.tempC > cfg.tempMaxAlerta && plant.msgTempEnviado !== 'alerta_alta') {
    event = { type: 'warn', text: `⚠️ ALERTA: Temperatura ALTA (${plant.tempC}°C). Activando enfriamiento.` };
    plant.msgTempEnviado = 'alerta_alta';
    shadow.reported.enfriamiento = true;
    shadow.reported.calentamiento = false;
} else if (plant.tempC < cfg.tempMinAlerta && plant.msgTempEnviado !== 'alerta_baja') {
    event = { type: 'warn', text: `⚠️ ALERTA: Temperatura BAJA (${plant.tempC}°C). Activando calentamiento.` };
    plant.msgTempEnviado = 'alerta_baja';
    shadow.reported.calentamiento = true;
    shadow.reported.enfriamiento = false;
} else if (plant.tempC >= cfg.tempMinAlerta && plant.tempC <= cfg.tempMaxAlerta && (plant.msgTempEnviado === 'alerta_alta' || plant.msgTempEnviado === 'alerta_baja')) {
    event = { type: 'ok', text: `✅ Temperatura estable (${plant.tempC}°C).` };
    plant.msgTempEnviado = 'estable';
}

if (plant.volumen > cfg.volumenMaxAlerta && plant.msgVolEnviado !== 'alerta_alta') {
    event = { type: 'warn', text: `📦 ALERTA: Volumen ALTO (${plant.volumen}%). Abriendo válvula de salida.` };
    plant.msgVolEnviado = 'alerta_alta';
    shadow.reported.valvula_salida = true;
} else if (plant.volumen < cfg.volumenMinAlerta) {
    let isCritical = plant.volumen <= 19;
    let currentState = isCritical ? 'alerta_baja_critica' : 'alerta_baja';
    if (plant.msgVolEnviado !== currentState) {
        let extraMsg = isCritical ? " Se requiere acción manual para volver a llenar el tanque." : "";
        event = { type: 'warn', text: `📦 ALERTA: Volumen BAJO (${plant.volumen}%).${extraMsg}` };
        plant.msgVolEnviado = currentState;
        shadow.reported.valvula_salida = false;
    }
} else if (plant.volumen >= cfg.volumenMinAlerta && plant.volumen <= cfg.volumenMaxAlerta && (plant.msgVolEnviado === 'alerta_alta' || plant.msgVolEnviado.startsWith('alerta_baja'))) {
    event = { type: 'ok', text: `✅ Volumen estable (${plant.volumen}%).` };
    plant.msgVolEnviado = 'estable';
}

if (plant.concentracion < cfg.concMin) {
    shadow.reported.led_concentracion = 'AZUL';
    shadow.reported.bomba_mezcla = true;
    shadow.reported.potencia_motor = 40;
    if (plant.msgConcEnviado !== 'baja') {
        event = { type: 'warn', text: `🔵 ALERTA: Concentración BAJA (${plant.concentracion} Brix). Potencia del motor al 40%.` };
        plant.msgConcEnviado = 'baja';
    }
} else if (plant.concentracion > cfg.concMax) {
    shadow.reported.led_concentracion = 'ROJO';
    shadow.reported.bomba_mezcla = true;
    shadow.reported.potencia_motor = 90;
    if (plant.msgConcEnviado !== 'alta') {
        event = { type: 'warn', text: `🔴 ALERTA: Concentración ALTA (${plant.concentracion} Brix). Potencia del motor al 90%.` };
        plant.msgConcEnviado = 'alta';
    }
} else if (plant.concentracion >= cfg.concMin && plant.concentracion <= cfg.concMax) {
    shadow.reported.led_concentracion = 'VERDE';
    shadow.reported.bomba_mezcla = false;
    shadow.reported.potencia_motor = 70;
    if (plant.msgConcEnviado === 'baja' || plant.msgConcEnviado === 'alta') {
        event = { type: 'ok', text: `🟢 Concentración normal (${plant.concentracion} Brix). Potencia del motor al 70%.` };
        plant.msgConcEnviado = 'normal';
    }
}

shadow.reported.alert_led = (shadow.reported.enfriamiento || shadow.reported.calentamiento || shadow.reported.valvula_salida || shadow.reported.bomba_mezcla);

global.set('PLANT', plant);
global.set('SHADOW', shadow);

const telemetry = {
    telemetry: {
        temperature_c: plant.tempC,
        volumen: plant.volumen,
        concentracion: plant.concentracion,
        led_status: shadow.reported.led_concentracion,
        status: shadow.reported.alert_led ? "CORRIGIENDO" : "ESTABLE"
    },
    actuadores: shadow.reported
};

let m1 = { topic: cfg.topicBase + '/telemetry', payload: telemetry };
let m2 = { topic: `$aws/things/${cfg.thingName}/shadow/update`, payload: { state: { reported: shadow.reported } } };
let m3 = event ? { payload: { text: event.text, type: event.type, ts: Date.now() } } : null;

return [m1, m2, m3];

const t = msg.topic || "";
if (t.endsWith("action/reset")) msg.topic = "action/reset";
if (t.endsWith("action/aumento_temperatura")) msg.topic = "action/aumento_temperatura";
if (t.endsWith("action/disminucion_temperatura")) msg.topic = "action/disminucion_temperatura";
if (t.endsWith("action/aumento_volumen")) msg.topic = "action/aumento_volumen";
if (t.endsWith("action/disminucion_volumen")) msg.topic = "action/disminucion_volumen";
if (t.endsWith("action/llenar_tanque")) msg.topic = "action/llenar_tanque";
if (t.endsWith("action/aumento_concentracion")) msg.topic = "action/aumento_concentracion";
if (t.endsWith("action/disminucion_concentracion")) msg.topic = "action/disminucion_concentracion";
return msg;

const p = msg.payload || {};

// 1) Notificación (texto + color por tipo)
let n = null;
if (p.text) {
    // Colores sugeridos por severidad
    const colorByType = {
        info: "#000000",
        warn: "#ff8c00",  // naranja
        error: "#cc0000",  // rojo
        ok: "#008000"   // verde
    };

    n = {
        payload: p.text,
        // FlowFuse Dashboard: puedes pasar ui_update para cambiar estilo
        ui_update: {
            // si tu ui-notification respeta color, úsalo
            color: colorByType[p.type] || "#000000"
        }
    };
}

// 2) Beep (solo si beep === true)
let b = null;
if (p.beep === true) {
    b = { payload: { beep: true, times: p.times || 2 } };
}

return [n, b];

const payload = msg.payload || {};
const tel = payload.telemetry || {};
const act = payload.actuadores || {};

const temp = (tel.temperature_c !== undefined) ? Number(tel.temperature_c) : 0;
const vol = (tel.volumen !== undefined) ? Number(tel.volumen) : 0;
const conc = (tel.concentracion !== undefined) ? Number(tel.concentracion) : 0;

const mTempGauge = { payload: temp };
const mVolGauge = { payload: vol };
const mConcGauge = { payload: conc };

const mTempChart = { topic: "Temperatura °C", payload: temp };
const mVolChart = { topic: "Volumen %", payload: vol };
const mConcChart = { topic: "Concentración Brix", payload: conc };

const alertLed = !!act.alert_led;
const ledConc = tel.led_status || "VERDE";
const potencia = act.potencia_motor !== undefined ? act.potencia_motor : 70;

const mk = (label, val, color) => ({ payload: val, ui_update: { label, color } });

let tempState = "STANDBY";
let tempColor = "gray";
if (act.enfriamiento) { tempState = "ENFRIANDO"; tempColor = "#00AAFF"; }
if (act.calentamiento) { tempState = "CALENTANDO"; tempColor = "#FF5500"; }
const mCompresor = mk("Temp Control", tempState, tempColor);

const mVSalida = mk("Válvula Salida", act.valvula_salida ? "ABIERTA" : "CERRADA", act.valvula_salida ? "orange" : "gray");

let potColor = "green";
if (potencia === 40) potColor = "blue";
if (potencia === 90) potColor = "red";
const mPotencia = mk("Potencia del motor", potencia + "%", potColor);

const mBomba = mk("Control de las Aspas", act.bomba_mezcla ? "ON" : "OFF", act.bomba_mezcla ? "green" : "gray");
const mLed = mk("Estado", alertLed ? "⚠️ ALERTA" : "✅ OK", alertLed ? "red" : "green");
const mBuzz = mk("Buzzer", alertLed ? "ON" : "OFF", alertLed ? "red" : "gray");
const mPhase = mk("Fase", tel.status || "ESTABLE", "black");
const mLedPanel = { payload: { colorLED: ledConc, temp, vol, conc } };

return [
    mTempGauge, mVolGauge, mConcGauge, // 1, 2, 3
    mTempChart, mVolChart, mConcChart, // 4, 5, 6
    mCompresor, mVSalida, mPotencia,   // 7, 8, 9 
    mBomba, mLed, mBuzz,               // 10, 11, 12
    mPhase, mLedPanel                  // 13, 14
];
